#!/bin/bash
set -e
echo "🖼️ Fix couvertures — suppression HEAD request..."
cd "$(git rev-parse --show-toplevel)"
python3 - << 'INNER'
import base64
open("src/lib/cover-utils.ts", "wb").write(base64.b64decode(""))
print("OK")
INNER
git add src/lib/cover-utils.ts
git commit -m "fix: remove HEAD request validation — was blocking valid covers on Vercel"
git push
echo "🎉 Déployé !"
